// ============================================================
// 猪场管理 API
// ============================================================

import axios from 'axios'

const BASE_URL = '/api'

/**
 * 获取所有猪场列表
 * @returns {Promise<{success: boolean, data: Array<{id: number, name: string, created_at: string}>}>}
 */
export async function getFarms() {
  const response = await axios.get(`${BASE_URL}/farms`)
  return response.data
}

/**
 * 获取单个猪场信息
 * @param {number} farmId
 * @returns {Promise<{success: boolean, data: {id: number, name: string, created_at: string}}>}
 */
export async function getFarm(farmId) {
  const response = await axios.get(`${BASE_URL}/farms/${farmId}`)
  return response.data
}

/**
 * 创建新猪场
 * @param {string} name
 * @returns {Promise<{success: boolean, data: {id: number, name: string, created_at: string}}>}
 */
export async function createFarm(name) {
  const response = await axios.post(`${BASE_URL}/farms`, { name })
  return response.data
}

/**
 * 更新猪场信息
 * @param {number} farmId
 * @param {string} name
 * @returns {Promise<{success: boolean, data: {id: number, name: string, created_at: string}}>}
 */
export async function updateFarm(farmId, name) {
  const response = await axios.put(`${BASE_URL}/farms/${farmId}`, { name })
  return response.data
}

/**
 * 删除猪场
 * @param {number} farmId
 * @returns {Promise<{success: boolean, message: string}>}
 */
export async function deleteFarm(farmId) {
  const response = await axios.delete(`${BASE_URL}/farms/${farmId}`)
  return response.data
}

/**
 * 获取猪场统计数据
 * @param {number} farmId
 * @returns {Promise<{success: boolean, farm_info: object, total_stats: object, daily_stats: array}>}
 */
export async function getFarmStats(farmId) {
  const response = await axios.get(`${BASE_URL}/farm-stats/${farmId}`)
  return response.data
}

/**
 * 获取检测统计数据
 * @param {number} farmId
 * @returns {Promise<{success: boolean, data: object}>}
 */
export async function getDetectionStats(farmId) {
  const params = farmId ? { farm_id: farmId } : {}
  const response = await axios.get(`${BASE_URL}/detection-stats`, { params })
  return response.data
}

/**
 * 获取检测记录
 * @param {number} farmId
 * @param {number} page
 * @param {number} pageSize
 * @returns {Promise<{success: boolean, data: array, total: number}>}
 */
export async function getDetectionRecords(farmId, page = 1, pageSize = 50) {
  const params = {
    page,
    page_size: pageSize
  }
  if (farmId) {
    params.farm_id = farmId
  }
  const response = await axios.get(`${BASE_URL}/detection-records`, { params })
  return response.data
}
